INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('4ki3blRlp7GZCy7rPMAY', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'ชลบุรีเลือกตั้งเดือด! เปิดโผ 93 ผู้สมัคร ส.ส. 10 เขต ชิงชัย 8 ก.พ. 69

ชาวชลบุรีเตรียมตัวให้พร้อม! 🗳️
ศึกเลือกตั้งซักฟอกเมืองชลครั้งนี้ร้อนแรง กับผู้สมัครรวม 93 คน จากหลากหลายพรรคการเมือง
ใครอยู่ในเขตไหน อยากเช็กเบอร์-เช็กพรรคของคนที่ใช่ คลิกลงมาเลย 👇

---

📍 เขต 1: อ.เมืองชลบุรี (โซนชายทะเล/บางแสน) 🌊
เบอร์ 1 – นายสุชาติ ชมกลิ่น (ภูมิใจไทย)
เบอร์ 4 – นายรัฐรุจน์ ปิยะพงศ์ภัทร์ (เพื่อไทย)
เบอร์ 7 – นายวรท ศิริรักษ์ (ประชาชน)
เบอร์ 2 – รวมไทยสร้างชาติ | เบอร์ 3 – พลังประชารัฐ | เบอร์ 6 – ประชาธิปัตย์

📍 เขต 2: อ.เมืองชลบุรี (โซนตัวเมือง/นาป่า) 🏢
เบอร์ 1 – น.ส.วรรณิดา นพสิทธิ์ (ประชาชน)
เบอร์ 3 – นายธนวัฒน์ ภาวสุทธิ์ (ภูมิใจไทย)
เบอร์ 6 – นายคงพัชร ไขรัศมี (เพื่อไทย)
เบอร์ 5 – ร้อยเอก จองชัย วงศ์ทรายทอง (ประชาธิปัตย์)

📍 เขต 3: อ.พานทอง / อ.บ้านบึง (บางส่วน) 🚜
เบอร์ 1 – นายชวาล พลเมืองดี (ประชาชน)
เบอร์ 2 – ร.ต.อ.สิทธิพัฒน์ ภาวสุทธิ์ (ภูมิใจไทย)
เบอร์ 5 – นายพายุ เนื่องจำนงค์ (เพื่อไทย)

📍 เขต 4: อ.บ้านบึง / อ.บ่อทอง / อ.หนองใหญ่ 🪵
เบอร์ 2 – น.ส.นภัสวรรณ มณีรัตน์โรจน์ (ประชาชน)
เบอร์ 3 – นายลิขิต อัศวจารุวรรณ (เพื่อไทย)
เบอร์ 5 – นายจิรวุฒิ สิงห์โตทอง (ภูมิใจไทย)

📍 เขต 5: อ.พนัสนิคม / อ.เกาะจันทร์ 🧺
เบอร์ 3 – นายอนันต์ ปรีดาสุทธิจิตต์ (ภูมิใจไทย)
เบอร์ 6 – นายณรงธร โพธิ์หมื่น (ประชาชน)
เบอร์ 7 – นายประมวล เอมเปีย (เพื่อไทย)

📍 เขต 6: อ.ศรีราชา (บางส่วน) / อ.เกาะสีชัง 🛳️
เบอร์ 1 – นายษรกฤต ผลลูกอินทร์ (เพื่อไทย)
เบอร์ 7 – นางนฤมาศ เปี่ยมบัณฑิต (ประชาชน)
เบอร์ 8 – นายสุรสิทธิ์ นิธิวุฒิวรรักษ์ (ภูมิใจไทย)

📍 เขต 7: อ.ศรีราชา (โซนอุตสาหกรรม) 🏭
เบอร์ 1 – นายสหัสวัต คุ้มคง (ประชาชน)
เบอร์ 5 – นายนฤพล นิยมทรัพย์ (เพื่อไทย)
เบอร์ 6 – นายสงกรานต์ ภาชนะ (ภูมิใจไทย)

📍 เขต 8: อ.บางละมุง (บางส่วน) 🏖️
เบอร์ 3 – นายชาญยุทธ เฮงตระกูล (เพื่อไทย)
เบอร์ 5 – นายเชาวลิตร แสงอุทัย (ภูมิใจไทย)
เบอร์ 7 – น.ส.มนัสวิน จันทร์เจริญ (ประชาชน)

📍 เขต 9: อ.บางละมุง (โซนพัทยา) 🌆
เบอร์ 5 – นายยอดชาย พึ่งพร (ประชาชน)
เบอร์ 6 – นายรัฐกิจ เฮงตระกูล (เพื่อไทย)
เบอร์ 8 – นายแมน อินทร์พิทักษ์ (ภูมิใจไทย)

📍 เขต 10: อ.สัตหีบ (ฐานทัพเรือ) ⚓
เบอร์ 2 – นายพนธกร ใคร่ครวญ (ภูมิใจไทย)
เบอร์ 3 – นายอัครเศรษฐ รักษ์สกุลสงสัย (เพื่อไทย)
เบอร์ 5 – นายธนาธาร ประมูลพงษ์ (ประชาชน)
เบอร์ 7 – นายสะถิระ เผือกประพันธุ์ (กล้าธรรม)

---

