INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('4qNLW1lNcb8Meg1pB3si', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '🍜✨ มาม่าทรงเครื่องอัพเลเวล! 5 สูตรลับเปลี่ยนบะหมี่สำเร็จรูปให้เป็นเมนูโปรด!

<p>เบื่อมาม่าแบบเดิมๆ แล้วใช่มั้ย? 🥺 ใครว่ามาม่าทำได้แค่มื้อสิ้นเดือน! วันนี้เรามี 5 สูตรลับมาม่าทรงเครื่องที่จะเปลี่ยนบะหมี่สำเร็จรูปธรรมดาๆ ให้กลายเป็นเมนูสุดปัง อร่อยลืมโลก แถมทำง่ายแสนง่าย!</p><p><br></p><p><br></p><p>✨ **สูตรที่ 1: มาม่าต้มยำกุ้งน้ำข้น** เพิ่มกุ้งสดๆ เห็ดฟาง และพริกเผา รับรองแซ่บซี๊ดถึงใจ!</p><p><br></p><p>🌶️ **สูตรที่ 2: มาม่าผัดขี้เมาทะเล** ใส่ปลาหมึก กุ้ง หอยแมลงภู่ ผัดกับเครื่องขี้เมาหอมๆ ฟินสุดๆ!</p><p><br></p><p>🥚 **สูตรที่ 3: มาม่าไข่ข้นชีส** ราดไข่ข้นเยิ้มๆ โปะด้วยชีสยืดๆ อร่อยนัวเกินต้าน!</p><p><br></p><p>🥓 **สูตรที่ 4: มาม่าหมูสับทรงเครื่อง** เพิ่มหมูสับรวน ปรุงรสด้วยน้ำปลา พริกป่น มะนาว โรยหน้าด้วยผักชี ต้นหอม อิ่มอร่อยคุ้มค่า!</p><p><br></p><p>🍜 **สูตรที่ 5: มาม่าเย็นตาโฟ** เติมซอสเย็นตาโฟ ลูกชิ้นปลา เลือดหมู ผักบุ้งกรอบ อร่อยเหมือนกินที่ร้าน!</p><p><br></p><p><br></p><p>อยากรู้สูตรละเอียดและเคล็ดลับความอร่อยแบบจัดเต็ม? 🤤 **คลิกเลย!** [ใส่ลิงก์ไปยังบทความฉบับเต็ม]</p><p><br></p><p><br></p><p>อย่ารอช้า! ไปลองทำตามกันเลย แล้วมาอวดมาม่าทรงเครื่องสุดครีเอทีฟของคุณในคอมเมนต์กันนะ! 👇 #มาม่าทรงเครื่อง #อร่อยบอกต่อ #เมนูสิ้นเดือน #ทำเองกินเอง #อร่อยลืมโลก</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community%2F1768894244542_IMG_3938.jpeg?alt=media&token=b394febf-8dfc-49b6-b889-ee3db77c0dfb","type":"image"}]', 'tip', 'active', 0, 0, 651, 1768894331934, 1768894331934);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('50Bs8CcNCNF6m7r07OOu', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'ชีวิตนี้ที่รอคอย ✨ ชีวิตหรูหราที่จับต้องได้! 💎💸 #ชีวิตดี๊ดี #LuxuryLife #MillionaireMindset #แรงบันดาลใจ

<p>เบื่อชีวิตเดิมๆ ซ้ำซากจำเจอยู่รึเปล่า? 🤔 มองหาแรงบันดาลใจในการสร้างชีวิตหรูหราในฝันอยู่ไหม? 🤩 ไม่ว่าจะเป็นการเดินทางรอบโลก ✈️ ดินเนอร์สุดหรู 🥂 หรือการลงทุนที่ชาญฉลาด 📈 ที่นี่คือจุดเริ่มต้นของคุณ! </p><p>👉 **คอมเมนต์** บอกเราว่าอะไรคือ ''ชีวิตหรูหรา'' ในแบบของคุณ! 👇 #RichLife #WealthyLifestyle #FYP #DreamBig</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769759313452_This%20Life%20%F0%9F%92%8E%F0%9F%92%B8%20%23rich%20%23luxury%20%23wealthylifestyle%20%23millionaire%20%23fyp.mp4?alt=media&token=6a6b6dc3-7573-4234-977e-83589a264f93","type":"video"}]', 'video', 'active', 2, 0, 501, 1769759350026, 1769759350026);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('9A6xDMxXEPlMw8fll3Xe', 'Pdy8haL5eIY6geccebaYDROCHmd2', '☺️✨️สมสมสมน้ำหน้า จินตหรามาแรง✨️

☺️✨️สมสมสมน้ำหน้า จินตหรามาแรง✨️', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2Fvideos%2F1770392150057_0.mp4?alt=media&token=96d09d20-4646-46bf-b558-5098d77e2998","type":"video"}]', 'video', 'active', 2, 0, 566, 1770392162106, 1770392162106);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('AJNBwcLA11TUU9PZNjHC', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '✨🚢 #iconsiam ชมวิวเจ้าพระยา สุดฟิน! กับ #royalprincesscruise 👑 #MargulAndTr... 📸

<p>เตรียมตัวพบกับค่ำคืนสุดพิเศษ! 🌃 ล่องเรือสำราญ #RoyalPrincessCruise 🚢 ชมวิว #iconsiam ริมแม่น้ำเจ้าพระยา 🌉 ที่สวยงามตระการตา ✨ พร้อมอาหารค่ำสุดหรู 🍽️ บรรยากาศโรแมนติก 💖 อย่าพลาดเก็บภาพความประทับใจ 📸 กับ #MargulAndTr... แล้วมาสนุกด้วยกันนะคะ! 🎉</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1770384902608_858.mp4?alt=media&token=70e97ce9-4cb2-4cb6-beee-aeea925fa07f","type":"video"}]', 'video', 'active', 1, 0, 568, 1770384951719, 1770384951719);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('Cqvk3xMNNAz5IosQV7Zn', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '🛢️😱 ขุดเจอ "บ่อน้ำมัน" หลังบ้าน! ชีวิตพลิกผันรวยพันล้าน!? (สปอยหนังสุดพีค)

<p>เคยฝันไหมว่าชีวิตจะพลิกผันรวยแบบไม่ทันตั้งตัว? 💸 เรื่องราวในหนังเรื่องนี้จะทำให้คุณตาโต! เมื่อชายหนุ่มธรรมดาๆ คนหนึ่งบังเอิญขุดเจอ "บ่อน้ำมัน" หลังบ้าน! 😲 ชีวิตจากหน้ามือเป็นหลังมือ รวยล้นฟ้าภายในพริบตา! </p><p><br></p><p><br></p><p>แต่ความรวยที่ได้มาง่ายๆ มักมีเงื่อนงำ! 😈 เรื่องราวสุดปั่นป่วน ชวนติดตาม เริ่มต้นขึ้น! ความโลภ, การหักหลัง, และความลับดำมืดที่ถูกซ่อนไว้ใต้ผืนดิน... เขาจะรักษาสมบัติมหาศาลนี้ไว้ได้หรือไม่? 🤔</p><p><br></p><p><br></p><p>🎬 เตรียมตัวพบกับเรื่องราวความตื่นเต้นเร้าใจ ที่จะทำให้คุณนั่งไม่ติดเก้าอี้! เราจะสปอยเนื้อเรื่องแบบจัดเต็ม! เผยทุกฉากเด็ด! ไขปมทุกปริศนา! รับรองว่าดูจบแล้วต้องร้องว้าว! 😮</p><p><br></p><p><br></p><p>🔥 อย่าพลาด! กดเข้าไปอ่านสปอยหนังสุดมันส์ได้เลย! คลิกที่นี่ 👉 [ใส่ลิงก์บทความ/วิดีโอของคุณ]</p><p><br></p><p><br></p><p>💬 แล้วคุณล่ะ? ถ้าเจอ "บ่อน้ำมัน" หลังบ้าน จะทำอะไรเป็นอย่างแรก? คอมเมนต์บอกเราหน่อย! 👇</p>', '[{"url":"https://youtu.be/tyRnWbWqgys?si=dFXpuSJyoJeTZoQ3","type":"youtube"}]', 'video', 'active', 1, 0, 627, 1769531069843, 1769531069843);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('Cyyf16VpybM9t1J8K9p6', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '👑 สปอยล์ The Princess (2022) แบบไม่กั๊ก! แอ็คชั่นสุดมันส์ เจ้าหญิงสุดแกร่ง ⚔️ พร้อมคำถามชวนคุย!

<p>ใครกำลังหาหนังบู๊แอ็คชั่นมันส์ๆ ที่มีเจ้าหญิงสุดสตรองต้องห้ามพลาด! 🤩 The Princess (2022) คือคำตอบ! เตรียมตัวพบกับการสปอยล์แบบจัดเต็ม! 🔥</p><p><br></p><p><br></p><p>**เรื่องย่อแบบคร่าวๆ:** เจ้าหญิง (Joey King) ถูกจับขังไว้ในหอคอยเพราะเธอไม่ยอมแต่งงานกับคนที่เธอไม่ได้รัก! แต่ใครจะรู้ว่าเจ้าหญิงคนนี้ไม่ใช่สาวน้อยบอบบาง เธอคือยอดนักสู้ที่พร้อมจะแหกคุกและล้างแค้น! 💥</p><p><br></p><p><br></p><p>**สิ่งที่เราชอบ:**</p><p><br></p><p>*   ฉากแอ็คชั่นคือดี! ต่อย เตะ ฟันดาบ แบบไม่ยั้ง! 🗡️</p><p><br></p><p>*   Joey King เอาอยู่! แสดงเป็นเจ้าหญิงนักสู้ได้เท่สุดๆ 👍</p><p><br></p><p>*   เนื้อเรื่องอาจจะไม่ได้ซับซ้อนมาก แต่ดูเพลิน สนุกตลอดทั้งเรื่อง!</p><p><br></p><p><br></p><p>**สปอยล์ (ระวัง! อาจเสียอรรถรสในการชม):**</p><p><br></p><p>*   [ใส่รายละเอียดเนื้อเรื่องสำคัญๆ ที่น่าสนใจ 2-3 จุด]</p><p><br></p><p>*   [ใส่รายละเอียดเนื้อเรื่องสำคัญๆ ที่น่าสนใจ 2-3 จุด]</p><p><br></p><p>*   [ใส่รายละเอียดเนื้อเรื่องสำคัญๆ ที่น่าสนใจ 2-3 จุด]</p><p><br></p><p><br></p><p>**โดยรวม:** The Princess (2022) เป็นหนังแอ็คชั่นที่ดูสนุก คลายเครียดได้ดี ใครชอบหนังบู๊แบบไม่คิดอะไรมาก แนะนำเลย!</p><p><br></p><p><br></p><p>**คำถามชวนคุย:**</p><p><br></p><p>*   ฉากไหนในเรื่องที่คุณชอบที่สุด? 🤔</p><p><br></p><p>*   คิดว่าใครเป็นตัวร้ายที่น่าหมั่นไส้ที่สุด? 😈</p><p><br></p><p>*   ถ้าเป็นคุณ คุณจะทำยังไงถ้าโดนจับแต่งงานกับคนที่ไม่รัก? 🤷‍♀️</p><p><br></p><p><br></p><p>**💬 มาคอมเมนต์พูดคุยกันได้เลย! แล้วอย่าลืมกดไลค์ กดแชร์ให้เพื่อนๆ ที่ชอบหนังแอ็คชั่นได้ดูกันด้วยนะ! 🎬 #ThePrincess #สปอยหนัง #หนังแอ็คชั่น #เจ้าหญิงนักสู้**</p>', '[{"url":"https://youtu.be/YNLYOKlKObc?si=pTGjvHaFUeBTHjqo","type":"youtube"}]', 'video', 'active', 2, 0, 643, 1769534250526, 1769534250526);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('GBr0vDVB4sDFFt0v7MUq', 'super-admin', 'ลู่ฝาน เปิดระบบปะทะเหล่าเทพ ep2', '[{"url":"https://pub-7e55074f08794361aaf305c1967f6ffa.r2.dev/videos/1771676410129_lufan-ep2.mp4","type":"video"}]', 'general', 'active', 4, 0, 187, 1771676415094, 1771676415094);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('GkRy0WKzWguWkhV3v5v5', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'แม่ฮ่องสอน 🛶 #ล่องเรือบ้านรักไทย 🇨🇳🇹🇭 ชมวิวสุดปัง! ✨

<p>เตรียมตัวพบกับทริปสุดชิลล์ที่แม่ฮ่องสอน! ⛰️ เราจะไป #ล่องเรือบ้านรักไทย 🛶 หมู่บ้านชาวจีนยูนนานที่สวยงามราวกับภาพวาด 🇨🇳 สัมผัสอากาศบริสุทธิ์ 🍃 ชมวิวทะเลสาบสุดลูกหูลูกตา 🏞️ และลิ้มลองชาหอมกรุ่น 🍵 อย่าลืมเตรียมกล้องไปเก็บภาพความประทับใจกันนะ! 📸 #แม่ฮ่องสอน #เที่ยวไทย #บ้านรักไทย #MaeHongSon #Thailand 🇹🇭</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769759672620_%23%E0%B9%81%E0%B8%A1%E0%B9%88%E0%B8%AE%E0%B9%88%E0%B8%AD%E0%B8%87%E0%B8%AA%E0%B8%AD%E0%B8%99%20%23%E0%B8%A5%E0%B9%88%E0%B8%AD%E0%B8%87%E0%B9%80%E0%B8%A3%E0%B8%B7%E0%B8%AD%E0%B8%9A%E0%B9%89%E0%B8%B2%E0%B8%99%E0%B8%A3%E0%B8%B1%E0%B8%81%E0%B9%84%E0%B8%97%E0%B8%A2%20.mp4?alt=media&token=f12ee069-480a-447a-b71b-1e64afcc4f6a","type":"video"}]', 'video', 'active', 5, 1, 510, 1769759693669, 1769759693669);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('Gkvbk0VOonJMxjaOzoh6', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '🤫 แผนรักซ่อนร้ายของ ''คุณหนู'' ที่คุณต้องรู้! (สปอยจัดเต็ม ไม่กลัวโดนด่า!) 🍿

<p>เตรียมตัวกรี๊ด! เพราะวันนี้เราจะมา **สปอยหนัง** เรื่อง ''คุณหนูแผนรักซ่อนร้าย'' แบบ **เจาะลึกทุกเม็ด!** 🤯 ไม่ว่าจะเป็นเบื้องหลังความแสบของนางเอก, กลเม็ดเคล็ดลับในการตกพระเอกสุดหล่อ, หรือแม้กระทั่งฉากจบสุดพีคที่คุณคาดไม่ถึง! 😱</p><p><br></p><p><br></p><p>**ทำไมคุณต้องอ่านสปอยนี้?**</p><p><br></p><p><br></p><p>*   **ประหยัดเวลา:** ขี้เกียจดูหนังยาวๆ? อ่านสปอยของเราจบ รับรองรู้เรื่องหมด! 😉</p><p><br></p><p>*   **เตรียมพร้อมก่อนดูจริง:** อยากรู้ว่าหนังสนุกจริงไหม? อ่านสปอยของเราก่อนตัดสินใจ! 🤔</p><p><br></p><p>*   **คุยกับเพื่อนรู้เรื่อง:** ไม่อยากตกเทรนด์? อ่านสปอยของเรา รับรองอินทุกกระแส! 😎</p><p><br></p><p><br></p><p>**แต่เดี๋ยวก่อน!** สปอยของเราไม่ได้มีแค่เนื้อเรื่องย่อๆ นะ! เรายังมี:</p><p><br></p><p><br></p><p>*   **วิเคราะห์ตัวละคร:** เจาะลึกถึงจิตใจและความคิดของตัวละครแต่ละตัว</p><p><br></p><p>*   **ฉากประทับใจ:** คัดมาเน้นๆ ฉากที่ทำให้คุณต้องเสียน้ำตา หรือหัวเราะจนท้องแข็ง</p><p><br></p><p>*   **เกร็ดเล็กเกร็ดน้อย:** ข้อมูลเบื้องหลังการถ่ายทำที่คุณอาจไม่เคยรู้</p><p><br></p><p><br></p><p>**พร้อมหรือยังที่จะดำดิ่งสู่โลกแห่งแผนรักซ่อนร้าย?**</p><p><br></p><p><br></p><p>**คลิกเลย!** 👇 เพื่ออ่านสปอยแบบจัดเต็ม! รับรองว่าคุณจะไม่ผิดหวัง! 🔥</p><p><br></p><p><br></p><p>[ลิงก์ไปยังบทความสปอยหนัง]</p><p><br></p><p><br></p><p>**อย่าลืม!** กดไลค์ กดแชร์ ให้เพื่อนๆ ได้อ่านด้วยนะ! 🙏</p>', '[{"url":"https://youtu.be/sCkxSm5BsOY?si=krlykjsp0LInwZ5u","type":"youtube"}]', 'video', 'active', 1, 0, 631, 1769531462863, 1769531462863);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('IC2ZRGtvoKbGydb289GV', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'Amazing Skydiving! 🪂☁️ ชมวิวสวยๆ บนฟ้าไปกับเรา! 🤩

<p>Amazing skydiving 🪂 Follow us for more amazing aerial adventures! ✈️ ชมวิวสวยๆ สุดลูกหูลูกตา 🤩 แล้วคุณจะหลงรัก! ❤️ #skydiving #foryoupage #jump #adventure #adrenaline #sky #beautifulview 🏞️</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769760075313_Amazing%20skydiving%20%F0%9F%AA%82%20%20Follow%20us%20for%20more-!%20%23skydiving%20%23foryoupage%20%23jum....mp4?alt=media&token=71999a0a-0358-46c9-b231-b3e425a0897b","type":"video"}]', 'video', 'active', 3, 0, 536, 1769760087782, 1769760087782);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('InHdc1LrMss5RRAGV6Nl', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '🌅 หยุดโลกทั้งใบไว้ตรงหน้า! วิวสวยสะกดใจที่คุณเคยเห็น 📸

<p>เคยไหม...ที่ได้ยืนอยู่ตรงหน้าวิวสวยจนแทบลืมหายใจ? ภูเขาสูงตระหง่านตัดกับท้องฟ้าสีคราม, ทะเลสีมรกตที่คลื่นซัดสาดเบาๆ, ห</p><p>**อย่ารอช้า! ร่วมสนุกกัน แล้วมาแชร์ ''วิวสวยที่สุด'' ในความทรงจำของคุณกันเลย!** </p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769667924781_view.mp4?alt=media&token=69add45e-8636-4aff-8976-81aba6570861","type":"video"}]', 'video', 'active', 3, 0, 635, 1769667933129, 1769667933129);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('JLeHJLrzecxY4uFNYKKT', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '💔 สัญญารักลวงใจ: น้ำตาไหลพราก! สปอยล์ฉากพีค ที่คุณต้องรู้! 😭

<p>เตรียมทิชชู่ให้พร้อม! 😭 #สัญญารักลวงใจ กำลังจะทำให้หัวใจคุณแตกสลาย! 💔 ใครที่พลาดตอนล่าสุด บอกเลยว่าคุณพลาดฉากพีคสุดๆ ที่ทำเอาน้ำตาไหลพราก! 😭</p><p><br></p><p><br></p><p>เราจะไม่บอกว่าฉากนั้นคืออะไร... แต่บอกได้คำเดียวว่า ความรัก... ความเชื่อใจ... และคำสัญญา ทุกอย่างกำลังจะถูกทำลาย! 💥</p><p><br></p><p><br></p><p>**อยากรู้ไหมว่าเกิดอะไรขึ้น?** 🤔</p><p><br></p><p><br></p><p>* **กดไลค์** โพสต์นี้ แล้วเราจะใบ้เพิ่ม! 😉</p><p><br></p><p>* **คอมเมนต์** บอกความรู้สึกของคุณหลังดูตอนนี้! 💬</p><p><br></p><p>* **แชร์** ให้เพื่อนๆ เตรียมใจไปด้วยกัน! 📢</p><p><br></p><p><br></p><p>**และที่สำคัญ!** อย่าลืม **ติดตาม** เพจเราไว้ เพราะเราจะมาสปอยล์ (แบบไม่เยอะเกินไป) ทุกตอน! 🤩</p><p><br></p><p><br></p><p>#สัญญารักลวงใจ #ละครดีบอกต่อ #สปอยล์ละคร #น้ำตาไหล #พลาดไม่ได้ #รีวิวละคร #Drama #ThaiDrama #Spoiler #ต้องดู #แนะนำละคร #ความรัก #ดราม่า</p>', '[{"url":"https://youtu.be/AWUB1zCWifI?si=PF4MVsB8nPlAS7hC","type":"youtube"}]', 'video', 'active', 1, 0, 635, 1769532023330, 1769532023330);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('JpM5jNRY0rEz96n97Hjq', 'V46hmF3ptXQoDh8tJ43xZ5nt6gs2', '🔥Bangkok Hot🔥กระแต Thailand 🌟⚡', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2Fvideos%2F1770267994155_0.mp4?alt=media&token=eaa6fd85-97ff-44d6-9eed-9deb3cc0d528","type":"video"}]', 'General', 'active', 1, 0, 68, 1770268008734, 1770268008734);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('LWixjH7SZeALs6UEbaMo', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'รายงานอุบัติเหตุ: เครนก่อสร้างล้มทับขบวนรถไฟ บริเวณอำเภอสีคิ้ว จังหวัดนครราชสีมา

เมื่อวันที่ 14 มกราคม 2569 เวลาประมาณ 09:30 น. เกิดอุบัติเหตุเครนที่ใช้ในงานก่อสร้างโครงการรถไฟความเร็วสูงล้มทับขบวนรถไฟด่วนพิเศษที่ 21 เส้นทางกรุงเทพฯ - อุบลราชธานี บริเวณกิโลเมตรที่ 220 หลัก 9 หมู่ 11 บ้านถนนคต ตำบลสีคิ้ว อำเภอสีคิ้ว จังหวัดนครราชสีมา

อุบัติเหตุดังกล่าวส่งผลให้โบกี้รถไฟตกรางจำนวน 1 โบกี้ และเกิดเพลิงไหม้ในโบกี้อีก 1 โบกี้ เบื้องต้นมีรายงานผู้เสียชีวิตและผู้ได้รับบาดเจ็บหลายราย หน่วยงานที่เกี่ยวข้องได้แก่ อำเภอสีคิ้ว การรถไฟแห่งประเทศไทย ทีมกู้ชีพกู้ภัย องค์การบริหารส่วนตำบลในพื้นที่ มูลนิธิกู้ภัยพรหมธรรม สีคิ้ว และหน่วยงานในพื้นที่ ได้ร่วมกันให้ความช่วยเหลือและนำส่งผู้ได้รับบาดเจ็บไปยังโรงพยาบาล

ขณะนี้ สาเหตุของอุบัติเหตุกำลังอยู่ระหว่างการตรวจสอบโดยหน่วยงานที่เกี่ยวข้อง และจะมีการรายงานความคืบหน้าเพิ่มเติมต่อไป', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community%2F1768364856970_IMG_3884.jpeg?alt=media&token=1453ff1f-2c02-4eb5-81f4-8b852362c00e","type":"image"}]', 'news', 'active', 0, 0, 638, 1768364873075, 1768364873075);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('NkW2wcb6LNuWk8yOxRDk', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'คางทูมระบาดวัยรุ่น–วัยทำงาน หมอเตือน 3 อาการต้องสงสัย รีบแยกตัว–ฉีดวัคซีนลดเสี่ยงแพร่เชื้อ

คางทูม ระบาดใน วัยรุ่น-วัยทำงาน ถ้ามี 3 อาการดังนี้ให้สงสัยเลยว่าเป็น วัคซีนป้องกัน ฉีดยังไง กี่เข็ม รับมือติดเชื้อเป็นกลุ่มก้อน พบผู้ป่วยโรคคางทูมเพิ่มมากขึ้น โดยปกติในแต่ละปีจะพบผู้ป่วยโรคคางทูมในเด็กเล็กเป็นส่วนใหญ่ แต่ในปีนี้พบว่าผู้ป่วยจำนวนมากอยู่ในช่วงวัยรุ่น และวัยผู้ใหญ่ตอนต้น ซึ่งสะท้อนถึงความจำเป็นในการเฝ้าระวังและดูแลกลุ่มอายุเหล่านี้มากขึ้น แม้อาการจะไม่รุนแรง แต่แพร่กระจายง่าย แนวโน้มเกิดการระบาดเป็นกลุ่มก้อน

กรมควบคุมโรค แนะนำประชาชนเฝ้าระวังอาการ ป้องกันตนเอง และเข้ารับวัคซีนให้ครบตามเกณฑ์ เพื่อลดความเสี่ยงการแพร่ระบาดของโรคในชุมชน

โรคคางทูม คืออะไร
โรคคางทูม เป็นโรคติดเชื้อไวรัสที่ติดต่อได้ง่าย พบได้บ่อยในเด็กและวัยรุ่น แต่ผู้ใหญ่ก็สามารถป่วยได้ สาเหตุเกิดจากเชื้อไวรัสคางทูม ซึ่งอยู่ในกลุ่ม Paramyxovirus

โรคคางทูม อาการต้องสงสัย
ลักษณะเด่นของโรคนี้คือ แก้มบวม + มีไข้ + ปวดเคี้ยว ใครมี 3 อาการนี้ให้สงสัยไว้ก่อนว่าอาจเป็นคางทูม

โรคคางทูม ติดต่อกันอย่างไร
โรคคางทูมติดต่อผ่านทางละอองฝอยจากน้ำลาย น้ำมูก หรือเสมหะ เช่น การไอ จาม พูดใกล้ชิด การใช้แก้วน้ำ ช้อน หรือของใช้ร่วมกับผู้ป่วย การสัมผัสสิ่งของที่ปนเปื้อนเชื้อแล้วนำมือมาสัมผัสปากหรือจมูก

ผู้ป่วยสามารถแพร่เชื้อได้ตั้งแต่ประมาณ 1 ถึง 2 วันก่อนมีอาการบวม และแพร่เชื้อได้ต่อเนื่องราว 5 วันหลังเริ่มมีอาการ

วัคซีนคือเกราะป้องกันที่ดีที่สุด
การป้องกันที่ได้ผลดีที่สุดคือการฉีดวัคซีน MMR (หัด–คางทูม–หัดเยอรมัน) ให้ครบตามเกณฑ์

เด็ก ฉีดยังไง กี่เข็ม วัคซีนป้องกันโรคคางทูม
เด็กควรได้รับวัคซีนอย่างน้อย 2 เข็ม โดย เข็มที่ 1 อายุ 9 เดือน / เข็มที่ 2 อายุ 1 ปี 6 เดือน ตามแผนสร้างเสริมภูมิคุ้มกันโรค

วัยรุ่น ผู้ใหญ่ ฉีดยังไง กี่เข็ม วัคซีนป้องกันโรคคางทูม
วัยรุ่นและผู้ใหญ่ที่ไม่เคยฉีดหรือไม่ทราบประวัติการฉีด แนะนำให้รับวัคซีน 2 เข็ม ห่างกันอย่างน้อย 4 สัปดาห์

กลุ่มเสี่ยงคือใคร สถานที่ฉีดวัคซีนป้องกันโรคคางทูม
แนะนำกลุ่มที่ควรรับวัคซีนคือ นักเรียน นักศึกษา บุคลากรสาธารณสุข ผู้ทำงานหรืออยู่รวมกันเป็นกลุ่ม สามารถเข้ารับวัคซีนที่ โรงพยาบาลของรัฐ โรงพยาบาลเอกชน คลินิกเวชกรรม สถานพยาบาลของรัฐใกล้บ้าน (บางแห่งมีบริการฟรีตามสิทธิ)

ประโยชน์ของวัคซีน และอาการข้างเคียงหลังฉีด
หลังฉีดอาจมีไข้ต่ำ ๆ ปวด บวม แดงบริเวณที่ฉีด (หายได้เอง) ข้อควรระวัง สำหรับหญิงตั้งครรภ์ห้ามฉีด (ควรเว้นอย่างน้อย 1 เดือนก่อนตั้งครรภ์) ผู้ที่มีไข้หรือป่วยรุนแรง ควรเลื่อนการฉีดออกไป

ป้องกันโรคคางทูมและภาวะแทรกซ้อนรุนแรง ลดการแพร่เชื้อในโรงเรียน ชุมชน และครอบครัว นอกจากนี้ ขอแนะนำให้ประชาชนดูแลสุขอนามัยส่วนบุคคล ล้างมือบ่อย ๆ หลีกเลี่ยงการใช้ของร่วมกับผู้อื่น และหากพบว่ามีอาการเข้าข่ายโรคคางทูม ควรรีบพบแพทย์ และแยกตนเองจากผู้อื่นอย่างน้อย 5 วันหลังเริ่มมีอาการบวม เพื่อลดการแพร่เชื้อในครอบครัว โรงเรียน และชุมชน', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community%2F1768111231629_8a82a448_e356_47c0_99a3_96a1c83038d0.webp?alt=media&token=0e74d4ad-1dcc-46c4-8f45-cfe503b4cdf3","type":"image"}]', 'news', 'active', 1, 0, 607, 1768111308207, 1768111308207);
