<p>🤣555555#videofunny #prank</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769682146429_Part%203%F0%9F%A4%A3%23videofunny%20%23prank.mp4?alt=media&token=c04dec26-ec1b-4e91-87ae-1865a11a7f39","type":"video"}]', 'video', 'active', 3, 0, 626, 1769682173995, 1769682173995);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('OjS9t6UxS4qf3Cs2iRPv', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '🥶 หนาวนี้ต้องรอด! อุณหภูมิลดฮวบ ทั่วไทยเตรียมรับมืออากาศเย็นจัด 🧣

📣 ประกาศเตือนภัย! ประเทศไทยยังคงเผชิญกับอากาศหนาวเย็นต่อเนื่อง 🥶 โดยเฉพาะภาคเหนือและอีสาน หนาวจนต้องใส่เสื้อกันหนาวหลายชั้น! ส่วนภาคกลาง, ตะวันออก และใต้ตอนบน ก็อากาศเย็นถึงหนาวเช่นกัน อย่าประมาท! 🌡️

กรมอุตุฯ เตือน! มวลอากาศเย็นกำลังแรงแผ่ปกคลุม ทำให้ทั่วไทยอุณหภูมิลดลง 📉 ขอให้ทุกคนดูแลสุขภาพให้ดีนะ! ระวังไข้หวัด เล่นกีฬาก็ต้องวอร์มอัพให้พร้อม 💪 และอย่าลืม! อากาศแห้งๆ แบบนี้ ไฟไหม้ง่ายมาก ต้องระวังอัคคีภัยกันด้วยนะ 🚒

ชาวใต้ไม่ต้องน้อยใจ! ถึงฝนจะน้อย แต่ก็ยังมีตกปรอยๆ บ้างเล็กน้อย 🌧️ ใครที่วางแผนเที่ยวทะเลช่วงนี้ เช็คสภาพอากาศก่อนเดินทางด้วยนะ! คลื่นลมแรงพอสมควร 🌊

**พยากรณ์อากาศรายภาค (12 ม.ค.):**

*   **เหนือ:** หนาว + หมอกตอนเช้า ยอดดอยหนาวจัด น้ำค้างแข็ง! 🥶
*   **อีสาน:** หนาว + ลมแรง ยอดภูหนาวจัด! 🌬️
*   **กลาง:** เย็นถึงหนาว ❄️
*   **ตะวันออก:** เย็นถึงหนาว 💨
*   **ใต้:** เย็นในตอนเช้า + ฝนเล็กน้อย ☔
*   **กทม. และปริมณฑล:** อากาศเย็น 🏙️

**🌊 ชาวเรือโปรดทราบ!** อ่าวไทยตอนล่างคลื่นสูง 2 เมตร อ่าวไทยตอนบนและอันดามันคลื่นสูง 1-2 เมตร เดินเรือด้วยความระมัดระวัง! ⚓

**⚠️ อย่ารอช้า! เตรียมพร้อมรับมืออากาศหนาว!**

*   **เช็คอิน!** ใครไปเที่ยวที่ไหนอากาศหนาวๆ อย่าลืมแชร์รูปสวยๆ ให้เพื่อนๆ อิจฉา #หนาวนี้ที่เมืองไทย #เที่ยวไทยไม่ตกเทรนด์ 📸
*   **ช้อปเลย!** มองหาเสื้อกันหนาวอุ่นๆ ผ้าพันคอเก๋ๆ ได้ที่นี่! [ใส่ Link ร้านค้าออนไลน์ของคุณ] 🛍️
*   **ดูแลสุขภาพ!** อ่านเคล็ดลับดูแลสุขภาพช่วงหน้าหนาวได้ที่นี่! [ใส่ Link บทความสุขภาพ] 💊

**#อากาศหนาว #กรมอุตุนิยมวิทยา #เตือนภัย #ดูแลสุขภาพ #เที่ยวหน้าหนาว**', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community%2F1768112874351_250518_new_470190.jpg?alt=media&token=1ad313b9-e496-4e81-80fb-0bea75f66fd3","type":"image"}]', 'news', 'active', 0, 0, 608, 1768117738459, 1768117738459);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('QLGE8BYBncUTXrj3ZlRQ', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '💔 จ้าวบ่าวถูกเท! ฟังเพลงฮิตติดชาร์ต ที่จะทำให้คุณน้ำตาซึมไปกับความเศร้า 😭

<p>โอ้โห! ใครว่าความรักจะสวยงามเสมอไป? 😢 เพลง "จ้าวบ่าวถูกเท" เพลงที่กำลังมาแรงที่สุดในตอนนี้ จะพาคุณดำดิ่งสู่ห้วงอารมณ์ของความผิดหวัง ความเสียใจ และความเจ็บปวดที่ถูกทิ้งไว้กลางทาง 💔</p><p><br></p><p><br></p><p>ฟังเพลงนี้แล้วคุณจะเข้าใจ... เข้าใจความรู้สึกของคนที่ถูกทิ้ง เข้าใจว่าการเริ่มต้นใหม่มันยากแค่ไหน และเข้าใจว่าบางครั้ง... การปล่อยวางก็เป็นทางออกที่ดีที่สุด 😔</p><p><br></p><p><br></p><p>🎤 เนื้อเพลงบาดลึกกินใจ ทำนองเศร้าเคล้าน้ำตา รับรองว่าฟังแล้วอินตามแน่นอน! ไม่ว่าคุณจะเคยมีประสบการณ์ตรง หรือแค่อยากสัมผัสความรู้สึกเศร้าๆ เพลงนี้ตอบโจทย์!</p><p><br></p><p><br></p><p>**อย่ารอช้า! รีบไปฟังเพลง "จ้าวบ่าวถูกเท" ได้แล้ววันนี้!**</p><p><br></p><p><br></p><p>👉 **คลิกที่นี่เพื่อฟังเพลง: [ใส่ Link เพลง]** 👈</p><p><br></p><p><br></p><p>แล้วมาแชร์ความรู้สึกของคุณหลังจากฟังเพลงนี้กันได้เลย! 👇 #จ้าวบ่าวถูกเท #เพลงเศร้า #เพลงฮิต #อกหัก #ความรัก #น้ำตา #ต้องฟัง #เพลงใหม่ #Music #SadSong</p>', '[{"url":"https://youtube.com/playlist?list=RDZRbIUzGpvzA&playnext=1&si=dvyuM5O5jyH7Qto2","type":"youtube"}]', 'video', 'active', 0, 0, 614, 1769534024942, 1769534024942);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('TYzpOfRgpPInJMB1pdHd', 'admin', '🎬 คนฉลาดก็พลาดได้! 😱 หนังสั้นสะท้อนสังคมที่คุณต้องดู! (ตอน 1)

<p>เคยไหม? ที่คิดว่าตัวเองฉลาด มั่นใจ แต่สุดท้ายกลับพลาดท่าเสียที… 😔</p><p><br></p><p><br></p><p>หนังสั้นเรื่องนี้จะพาคุณไปพบกับเรื่องราวที่อาจเกิดขึ้นกับใครก็ได้ แม้แต่คนที่คุณคิดว่า ''เพอร์เฟกต์'' ✨ พบกับบทเรียนราคาแพงที่สอนให้เรารู้ว่า ''ความประมาท'' คือจุดเริ่มต้นของความผิดพลาด</p><p><br></p><p><br></p><p>#หนังสั้นต้องมนต์ฟิล์ม เรื่อง ''คนฉลาดก็พลาดได้'' ตอนที่ 1 จะทำให้คุณทั้งอิน ทั้งลุ้น และฉุกคิด!</p><p><br></p><p><br></p><p>**ทำไมต้องดู?**</p><p><br></p><p>* ✅ เนื้อเรื่องเข้มข้น สะท้อนสังคมจริง</p><p><br></p><p>* ✅ นักแสดงถ่ายทอดอารมณ์ได้ดีเยี่ยม</p><p><br></p><p>* ✅ บทเรียนที่เตือนใจให้เราไม่ประมาท</p><p><br></p><p><br></p><p>**อย่ารอช้า! คลิกดูเลย!** 👇 [ใส่ Link หนังสั้นตรงนี้]</p><p><br></p><p><br></p><p>**ดูแล้วรู้สึกยังไง? คอมเมนต์บอกกันหน่อย!** 👇 #ละครสั้นสะท้อนสังคม #หนังใหม่น่าดู #คนฉลาดก็พลาดได้ #พลาดแล้วต้องแก้ไข #ต้องมนต์ฟิล์ม</p>', '[{"url":"https://youtu.be/BLlAu7Is68s?si=c1uZOytvOOqGd9KS","type":"youtube"}]', 'video', 'active', 1, 0, 632, 1769509163692, 1769509163692);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('VCssmaMXaXZeQlYge6en', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', 'แพนด้าซุ่มซ่ามแต่น่ารักสุดๆ 🐼💖 #แพนด้า #น่ารัก #แก๊งค์ #สวนสัตว์ #รัก

<p>โอ๊ยยย! ดูความซุ่มซ่ามของน้องแพนด้าสิคะ! 🐼😂 น่ารักจนใจเจ็บเลย! 🥰 ใครเป็น FC แพนด้าบ้างยกมือขึ้น 🙋‍♀️🙋‍♂️ #PandaLove #CuteAnimal #ZooLife #แพนด้าจ๋า</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1770384117794_533.mp4?alt=media&token=2c7f54bf-8016-40de-a69f-8a1368bc9f7f","type":"video"}]', 'video', 'active', 3, 0, 532, 1770384148252, 1770384148252);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('W2Qg31vjhYXQUxbWrAa3', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '💦 #น้ำตกแม่เตี๊ยะ สวรรค์ใกล้แค่เอื้อม! 🏕️ กางเต็นท์ชิลล์ ฟังเสียงธรรมชาติบำบัด 💚

<p>เบื่อเมืองกรุง...อยากหนีไปพักใจ? 🏞️ #น้ำตกแม่เตี๊ยะ ใน #อุทยานแห่งชาติออบหลวง นี่แหละคือคำตอบ! ✨</p><p><br></p><p><br></p><p>น้ำตกสวยใสไหลเย็นชื่นใจ 🌳 โอบล้อมด้วยธรรมชาติเขียวขจี อากาศบริสุทธิ์จนลืมหายใจไปเลย! 🏕️ ที่นี่เค้ามีจุดกางเต็นท์ให้ด้วยนะ จะนอนฟังเสียงน้ำไหลเคล้าเสียงจิ้งหรีดก็ฟินสุดๆ 🌌</p><p><br></p><p><br></p><p>#น้ำตกแม่เตี๊ยะ ไม่ได้มีดีแค่น้ำตกนะ! ยังมีเส้นทางเดินป่าให้เราได้สำรวจธรรมชาติกันแบบเต็มอิ่ม 🚶‍♀️🚶‍♂️ ใครที่ชอบถ่ายรูปบอกเลยว่าห้ามพลาด เพราะมุมสวยๆ เพียบ! 📸</p><p><br></p><p><br></p><p>ใครกำลังมองหาที่เที่ยวพักผ่อนใกล้ชิดธรรมชาติ แบบไม่ต้องเดินทางไกล #น้ำตกแม่เตี๊ยะ คือตัวเลือกที่ใช่แน่นอน! 💯</p><p><br></p><p>เครดิต</p><p>https://www.tiktok.com/@sornputeng?is_from_webapp=1&amp;sender_device=pc</p><p><br></p><p><br></p><p>#เที่ยวไทย #UnseenThailand #ธรรมชาติบำบัด #ที่เที่ยวเชียงใหม่ #ออบหลวง #น้ำตก #กางเต็นท์ #รีวิวเชียงใหม่ #Chiangmai #Thailand #Travel #Nature #Waterfall #Camping</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1769758878760_camping%20%F0%9F%8F%95%EF%B8%8F%20%23%E0%B8%99%E0%B9%89%E0%B9%8D%E0%B8%B2%E0%B8%95%E0%B8%81%E0%B9%81%E0%B8%A1%E0%B9%88%E0%B9%80%E0%B8%95%E0%B8%B5%E0%B9%8A%E0%B8%A2%E0%B8%B0%20%23%E0%B8%AD%E0%B8%B8%E0%B8%97%E0%B8%A2%E0%B8%B2%E0%B8%99%E0%B9%81%E0%B8%AB%E0%B9%88%E0%B8%87%E0%B8%8A%E0%B8%B2%E0%B8%95%E0%B8%B4%E0%B8%AD%E0%B8%AD%E0%B8%9A%E0%B8%AB%E0%B8%A5%E0%B8%A7%E0%B8%87%20%23%E0%B8%99%E0%B9%89%E0%B9%8D%E0%B8%B2%E0%B8%95%E0%B8%81%20%23%E0%B8%98%E0%B8%A3%E0%B8%A3%E0%B8%A1%E0%B8%8A%E0%B8%B2%E0%B8%95%E0%B8%B4%20....mp4?alt=media&token=2e2ea1dd-aca8-43cf-aa9d-0e5e5f521c00","type":"video"}]', 'video', 'active', 1, 0, 500, 1769759010550, 1769759010550);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('XNIyP3xXxc4QgXVBz8oI', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '💡 Wow! Good Idea! 👍

<p>Wow! Good idea! 🎉 ชอบไอเดียนี้มากๆ เลยค่ะ! ✨ เป็นไอเดียที่น่าสนใจสุดๆ 🤩 ลองเอาไปปรับใช้ดูนะคะ! 😉</p>', '[{"url":"https://youtube.com/shorts/K5vuFZCAcB4?si=0jsqR9R73d11wRe9","type":"youtube"}]', 'video', 'active', 2, 0, 715, 1769563476372, 1769563476372);
INSERT OR REPLACE INTO posts (id, user_id, content, media_urls, category, status, likes_count, comments_count, views_count, created_at, updated_at) VALUES ('ZU8GpUMdx8MIb54wtw6y', 'Ud9bec6d2ea945cf4330a69cb74ac93cf', '👀 สายตาข้ามีเพียงท่าน! ขอบตาดำก็ยอม! 🐼🤣 #เฉินเจ๋อหยวน #ซีรีย์จีน

<p>ติดซีรีย์หนักมาก! 💖😍 สายตาข้ามีแต่ #เฉินเจ๋อหยวน เท่านั้น! ถึงขอบตาดำเป็นหมีแพนด้า 🐼 ก็ยอม! ใครเป็นเหมือนกันบ้างยกมือขึ้น 🙌 #ซีรีย์จีน #ดูวนไป #พระเอกหล่อบอกต่อ</p>', '[{"url":"https://firebasestorage.googleapis.com/v0/b/appinjproject.firebasestorage.app/o/community_posts%2F1770384667178_915.mp4?alt=media&token=df633f31-d44c-4c28-99d1-8e5483a75f0a","type":"video"}]', 'video', 'active', 2, 0, 561, 1770384685171, 1770384685171);
